def lcs_len(a,b):
    # DP
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            t=dp[j]
            if a[i-1]==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=t
    return dp[m]

def sim_lcs_ratio(a,b):
    # normalized by length of longer string
    L = lcs_len(a,b)
    return L / max(len(a), len(b))

